# ── Helpers ────────────────────────────────────────────────────────────────────
def normalize_issue(issue):
    try:
        return str(int(str(issue)))
    except:
        return str(issue)

def _rate_limit_api():
    global _last_api_call
    with RATE_LIMIT_LOCK:  # FIX: Use separate lock (don't block pattern lookups)
        now     = time.time()
        elapsed = now - _last_api_call
        if elapsed < MIN_API_INTERVAL:
            time.sleep(MIN_API_INTERVAL - elapsed)
        _last_api_call = time.time()

def _rate_limit_tg():
    global _last_tg_call
    with RATE_LIMIT_LOCK:  # FIX: Use separate lock (don't block pattern lookups)
        now     = time.time()
        elapsed = now - _last_tg_call
        if elapsed < MIN_TG_INTERVAL:
            time.sleep(MIN_TG_INTERVAL - elapsed)
        _last_tg_call = time.time()

def _cleanup_tmp_file():
    tmp = STATE_FILE + '.tmp'
    try:
        if os.path.exists(tmp):
            os.remove(tmp)
    except Exception as e:
        logger.warning(f"Cleanup tmp failed: {e}")
