# ── Pattern Table Helper — load from Excel ────────────────────────────────────
def load_pattern_from_excel(xl_path):
    """
    Read AllPatterns sheet from Excel file → return {pattern_key: [s_count, b_count]} dict.
    S_Count, B_Count columns ကနေ pattern table ဆောက်သည်။
    Signal column override ပါ ထည့်သည် (flipped patterns အတွက်)。
    Returns {} if file not found or error.
    """
    try:
        import openpyxl
        wb = openpyxl.load_workbook(xl_path, read_only=True, data_only=True)
        ws = wb['AllPatterns']
        hdr = {}
        for i, cell in enumerate(next(ws.iter_rows(min_row=1, max_row=1))):
            if cell.value:
                hdr[cell.value] = i
        pat_i = hdr.get('Pattern')
        s_i   = hdr.get('S_Count')
        b_i   = hdr.get('B_Count')
        if pat_i is None or s_i is None or b_i is None:
            logger.warning("[EXCEL-LOAD] Missing Pattern/S_Count/B_Count column")
            return {}
        table = {}
        for row in ws.iter_rows(min_row=2, values_only=True):
            key = row[pat_i]
            s   = row[s_i]
            b   = row[b_i]
            if key and s is not None and b is not None:
                table[str(key)] = [int(s), int(b)]
        wb.close()
        logger.info(f"[EXCEL-LOAD] Loaded {len(table)} patterns from {xl_path}")
        return table
    except ImportError:
        logger.warning("[EXCEL-LOAD] openpyxl not installed")
        return {}
    except Exception as e:
        logger.warning(f"[EXCEL-LOAD] Failed: {e}")
        return {}
