# Total patterns: 100000 (5-number, from CSV 1,032,800 rows)
# ─────────────────────────────────────────────────────────────────────────────
class WaveUpBot:
    def __init__(self):
        _cleanup_tmp_file()

        # ── Infrastructure state ───────────────────────
        self.auth_token       = None
        self.fail_count       = 0
        self.net_fail_count   = 0
        self.last_issue       = None
        self.last_sent_sig    = None
        self.last_sent_win    = None
        self.wins             = 0
        self.losses_total     = 0
        self.consecutive_losses = 0
        self.bet_counter      = 0
        self.result_history   = []
        self.total_results    = 0
        self.bootstrapped     = False
        self._export_counter  = 0

        # ── _last_prediction ကို initialize + persist လုပ်ရမယ် ──
        # restart ဖြစ်ရင် pending prediction ပျောက်ပြီး win/loss miss ဖြစ်တယ်
        self._last_prediction = None
        # ────────────────────────────────────────────────────────────────────────

        # ── Formula state (5-Number Pattern Lookup) ────
        # Last 5 actual TRX numbers မှတ်ထား
        # Pattern table မှာ ရှာပြီး S/B predict
        self.last_5_nums = []   # e.g. [8,5,5,5,3]
        # ───────────────────────────────────────────────

        # ── Self-Learning state ────────────────────────
        self._last_pattern_key = None   # pattern used for pending prediction
        self._last_live_key    = None   # 5-number live tracking key (stored at prediction time)
        self.pattern_live      = {}     # {key: {'results':['W','L',...], 'updated':''}}
        self._recalc_counter   = 0      # counts rounds toward UPDATE_EVERY_LIVE
        self._recent_flips     = []     # patterns flipped in last recalculate cycle
        # ───────────────────────────────────────────────

        self._load_state()
        self._load_trx_history()
        logger.info(
            f"Mr Wai Trading Bot Ready! patterns={len(PATTERN_TABLE)} "
            f"history={len(self.result_history)} "
            f"W={self.wins} L={self.losses_total}"
        )

    # ══════════════════════════════════════════════════════════════════════════
    #  Telegram
    # ══════════════════════════════════════════════════════════════════════════
    def send_msg(self, text, max_retries=3, parse_mode=None):
        for attempt in range(max_retries):
            try:
                _rate_limit_tg()
                payload = {"chat_id": CHAT_ID, "text": text, "message_thread_id": TOPIC}
                if parse_mode:
                    payload["parse_mode"] = parse_mode
                r = requests.post(
                    f"https://api.telegram.org/bot{TOKEN}/sendMessage",
                    json=payload,
                    timeout=15
                )
                if r.status_code == 200:
                    try:
                        resp = r.json()
                        if resp.get('ok'):
                            return True
                        logger.warning(f"Telegram error ({attempt+1}): {resp.get('description','?')}")
                    except Exception as e:
                        logger.warning(f"Telegram JSON parse error ({attempt+1}): {e}")
                elif r.status_code == 429:
                    retry_after = r.headers.get('Retry-After', '5')
                    try:
                        # Try to parse as integer first (seconds)
                        wait_seconds = int(retry_after)
                    except (ValueError, TypeError):
                        # Fall back to 5 seconds if unparseable (could be HTTP-date)
                        wait_seconds = 5
                        logger.warning(f"Unparseable Retry-After header: {retry_after} → using 5s")
                    logger.warning(f"Telegram rate limit, waiting {wait_seconds}s")
                    time.sleep(wait_seconds)
                    continue
                else:
                    logger.warning(f"Telegram HTTP {r.status_code} ({attempt+1})")
            except requests.exceptions.Timeout:
                logger.warning(f"Telegram timeout ({attempt+1}), retrying...")
                continue
            except Exception as e:
                logger.warning(f"Telegram error ({attempt+1}): {e}")
            time.sleep(2)
        return False

    # ══════════════════════════════════════════════════════════════════════════
    #  API — Login & Data
    # ══════════════════════════════════════════════════════════════════════════
    def _create_sig(self, data):
        mutable = {k: v for k, v in data.items() if k not in ('signature', 'timestamp')}
        s = json.dumps(mutable, sort_keys=True, separators=(',', ':'))
        mutable['signature'] = hashlib.md5(s.encode()).hexdigest().upper()
        mutable['timestamp'] = int(datetime.datetime.now(datetime.timezone.utc).timestamp())
        return mutable

    def login(self, max_retries=5):
        for attempt in range(max_retries):
            try:
                _rate_limit_api()
                data = {
                    "language": 0, "logintype": "mobile", "phonetype": 0,
                    "pwd": PASSWORD,
                    "random": str(int(time.time() * 1_000_000)),
                    "username": LOGIN_ID
                }
                r = requests.post(
                    f"{API_BASE}/Login",
                    json=self._create_sig(data),
                    headers={'Content-Type': 'application/json', 'Referer': 'https://www.6lottery.com/'},
                    timeout=15
                )
                result = r.json()
                if result.get('code') == 0 and result.get('data'):
                    self.auth_token = result['data']['token']
                    logger.info("Login OK")
                    return True
                logger.warning(f"Login failed: {result.get('message','?')}")
            except Exception as e:
                logger.warning(f"Login error ({attempt+1}): {e}")
            time.sleep(3)
        return False

    def get_live_data(self, max_retries=5):
        if not self.auth_token:
            if not self.login():
                return None
        for attempt in range(max_retries):
            try:
                _rate_limit_api()
                params = {
                    "pageSize": 50, "pageNo": 1, "typeId": 13, "language": 0,
                    "random": str(int(time.time() * 1_000_000))
                }
                r = requests.post(
                    f"{API_BASE}/GetTRXNoaverageEmerdList",
                    json=self._create_sig(params),
                    headers={
                        'Content-Type': 'application/json',
                        'Authorization': f'Bearer {self.auth_token}',
                        'Referer': 'https://www.6lottery.com/'
                    },
                    timeout=15
                )
                result = r.json()
                if result.get('code') == 0 and result.get('data'):
                    self.net_fail_count = 0
                    self.fail_count     = 0
                    return result['data']['data']['gameslist']
                elif result.get('code') in [4, 5]:
                    self.auth_token = None
                    if self.login():
                        continue
                    else:
                        return None
            except Exception as e:
                self.net_fail_count += 1
                delay = NET_BACKOFF_DELAYS[min(self.net_fail_count - 1, len(NET_BACKOFF_DELAYS) - 1)]
                logger.warning(f"Net error ({attempt+1}) fail#{self.net_fail_count}: {e} — backoff {delay}s")
                if self.net_fail_count >= NET_FAIL_RELOGIN:
                    logger.warning("[NET-BACKOFF] 5 consecutive failures — force re-login")
                    self.auth_token     = None
                    self.net_fail_count = 0
                    if not self.login():
                        return None
                    continue
                time.sleep(delay)
                continue
        self.fail_count += 1
        if self.fail_count >= 2:
            self.auth_token = None
            self.fail_count = 0
        return None

    # ══════════════════════════════════════════════════════════════════════════
    #  History helpers
    # ══════════════════════════════════════════════════════════════════════════
    def _add_result(self, result):
        self.result_history.append(result)
        self.total_results += 1
        if len(self.result_history) > ROLLING_MAX:
            self.result_history = self.result_history[-ROLLING_MAX:]

    def bootstrap_history(self):
        if self.bootstrapped:
            logger.info("Already bootstrapped.")
            return True
        logger.info("Bootstrapping history...")
        if not self.auth_token and not self.login():
            return False
        try:
            _rate_limit_api()
            params = {
                "pageSize": 500, "pageNo": 1, "typeId": 13, "language": 0,
                "random": str(int(time.time() * 1_000_000))
            }
            r = requests.post(
                f"{API_BASE}/GetTRXNoaverageEmerdList",
                json=self._create_sig(params),
                headers={
                    'Content-Type': 'application/json',
                    'Authorization': f'Bearer {self.auth_token}',
                    'Referer': 'https://www.6lottery.com/'
                },
                timeout=30
            )
            result = r.json()
            all_results = (
                result.get('data', {}).get('data', {}).get('gameslist', [])
                if result.get('code') == 0 else []
            )
        except Exception as e:
            logger.warning(f"Bootstrap error: {e}")
            all_results = []
        if not all_results:
            logger.warning("Bootstrap: no data")
            return False
        all_results = list(reversed(all_results))[-500:]
        parsed = []
        trx_numbers = []  # NEW: Store actual TRX numbers (0-9)
        for g in all_results:
            try:
                num = int(g.get('number', -1))
                if num >= 0:
                    parsed.append('B' if num >= 5 else 'S')
                    trx_numbers.append(num)  # NEW: Collect TRX numbers
            except Exception as e:
                logger.warning(f"Bootstrap parse error: {e}")
        if len(parsed) < 20:
            return False
        
        # MERGE with existing history instead of truncating
        # Preserve all previous results + only add NEW ones from bootstrap
        old_history = self.result_history.copy() if hasattr(self, 'result_history') else []
        old_total = len(old_history)
        
        # Combine: keep old data + add new data (avoid duplicates)
        if old_history and parsed:
            # FIX: Use last 10 results as overlap signature (not single char)
            overlap_idx = 0
            overlap_len = min(10, len(old_history))
            if overlap_len >= 3:
                tail = old_history[-overlap_len:]
                # Search for this tail sequence in parsed data
                for start in range(len(parsed) - overlap_len + 1):
                    if parsed[start:start + overlap_len] == tail:
                        overlap_idx = start + overlap_len
                        break
            new_data = parsed[overlap_idx:]
        else:
            new_data = parsed
        
        merged_history = old_history + new_data
        self.result_history = merged_history[-ROLLING_MAX:]  # Keep last ROLLING_MAX
        self.total_results = len(self.result_history)
        self.bootstrapped = True
        
        logger.info(
            f"Bootstrap: Merged {old_total} existing + {len(new_data)} new → "
            f"{len(self.result_history)} total results"
        )
        
        # FIX: Store last 4 numbers (NOT 5) because run loop will append
        # the latest number again when it first processes it.
        # This prevents duplicate number bug on first prediction.
        if len(trx_numbers) >= 5:
            self.last_5_nums = trx_numbers[-5:-1]  # 4 nums before the latest
            logger.info(f"Bootstrap: Initialized last_5_nums = {self.last_5_nums} (4 nums, run loop adds 5th)")
        else:
            self.last_5_nums = []
            logger.warning(f"Bootstrap: Only {len(trx_numbers)} TRX numbers, need 5 for pattern")
        
        logger.info(f"Bootstrap done: {len(self.result_history)} results")
        self._save_state()
        return True

    # ══════════════════════════════════════════════════════════════════════════
    #  State save / load
    # ══════════════════════════════════════════════════════════════════════════
    def _build_state_dict(self):
        return {
            'consecutive_losses': self.consecutive_losses,
            'last_issue':         self.last_issue,
            'last_sent_sig':      self.last_sent_sig,
            'last_sent_win':      self.last_sent_win,
            'result_history':     self.result_history,
            'total_results':      self.total_results,
            'wins':               self.wins,
            'losses_total':       self.losses_total,
            'bootstrapped':       self.bootstrapped,
            # Formula state
            'last_5_nums':        self.last_5_nums,
            'last_prediction':    self._last_prediction,
            # Self-learning state
            'last_pattern_key':   self._last_pattern_key,
            'last_live_key':      self._last_live_key,  # Store live_key for consistent tracking
            'recalc_counter':     self._recalc_counter,
            'bet_counter':        self.bet_counter,
        }

    def _save_state(self):
        state = self._build_state_dict()
        tmp   = STATE_FILE + '.tmp'
        try:
            with open(tmp, 'w') as f:
                json.dump(state, f)
                f.flush()
                os.fsync(f.fileno())
            os.replace(tmp, STATE_FILE)
        except Exception as e:
            logger.warning(f"Save state failed: {e}")
            try:
                if os.path.exists(tmp):
                    os.remove(tmp)
            except Exception as e2:
                logger.warning(f"Remove tmp failed: {e2}")
        if self.total_results > 0:
            self._export_counter += 1
            if self._export_counter >= EXPORT_EVERY:
                self._export_counter = 0
                t = threading.Thread(target=self._export_to_github, daemon=True)
                t.start()
                t2 = threading.Thread(target=self._save_trx_history, daemon=True)
                t2.start()
                # ZIP export to GitHub (bot code + pattern_live.json + state)
                t3 = threading.Thread(target=self._export_zip_to_github, daemon=True)
                t3.start()

    def _load_state(self):
        token = GITHUB_TOKEN
        if token:
            try:
                logger.info("[RESTORE] Trying GitHub-first state restore...")
                r = requests.get(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{BACKUP_FILE}",
                    headers={'Authorization': f'token {token}'},
                    timeout=15
                )
                if r.status_code == 200:
                    content = r.json().get('content', '')
                    if content:
                        decoded = base64.b64decode(content).decode('utf-8')
                        with open(STATE_FILE, 'w') as f:
                            f.write(decoded)
                        logger.info("[RESTORE] GitHub restore SUCCESS!")
                elif r.status_code == 404:
                    logger.info("[RESTORE] No backup on GitHub yet — starting fresh")
                else:
                    logger.warning(f"[RESTORE] GitHub restore failed: {r.status_code}")
            except Exception as e:
                logger.warning(f"[RESTORE] GitHub restore error: {e}")
        try:
            if not os.path.exists(STATE_FILE):
                return
            with open(STATE_FILE, 'r') as f:
                state = json.load(f)
            defaults = {
                'consecutive_losses': 0,
                'last_issue':         None,
                'last_sent_sig':      None,
                'last_sent_win':      None,
                'result_history':     [],
                'total_results':      0,
                'wins':               0,
                'losses_total':       0,
                'bootstrapped':       False,
                'last_5_nums':        [],
                'last_live_key':      None,  # Restore live_key for consistent tracking
                'bet_counter':        0,
            }
            for k, v in defaults.items():
                setattr(self, k, state.get(k, v))
            raw_sig = state.get('last_sent_sig', None)
            self.last_sent_sig = normalize_issue(raw_sig) if raw_sig else None
            raw_win = state.get('last_sent_win', None)
            self.last_sent_win = normalize_issue(raw_win) if raw_win else None
            self.total_results = state.get('total_results', len(self.result_history))
            self._export_counter  = 0
            # _last_prediction restore
            self._last_prediction  = state.get('last_prediction', None)
            # Self-learning restore
            self._last_pattern_key = state.get('last_pattern_key', None)
            self._last_live_key    = state.get('last_live_key', None)  # Restore live_key
            self._recalc_counter   = state.get('recalc_counter', 0)
            self._load_pattern_live()
            # Downloads run in background — do NOT block bot startup
            threading.Thread(
                target=self._download_excel_zip_from_github, daemon=True
            ).start()
            threading.Thread(
                target=self._download_zip_from_github, daemon=True
            ).start()
        except Exception as e:
            logger.warning(f"Load state failed: {e}")

    # ══════════════════════════════════════════════════════════════════════════
    #  Self-Learning: Pattern Live Tracking
    # ══════════════════════════════════════════════════════════════════════════
    def _load_pattern_live(self):
        """Load live tracking data and restore overrides into PATTERN_OVERRIDES."""
        try:
            if os.path.exists(PATTERN_LIVE_FILE):
                with open(PATTERN_LIVE_FILE) as f:
                    data = json.load(f)
                self.pattern_live = data.get('tracking', {})
                # Restore live signal overrides
                for k, v in data.get('overrides', {}).items():
                    PATTERN_OVERRIDES[k] = v
                logger.info(
                    f"[SELF-LEARN] Loaded: {len(self.pattern_live)} tracked patterns, "
                    f"{len(PATTERN_OVERRIDES)} overrides active"
                )
        except Exception as e:
            logger.debug(f"Load pattern_live failed: {e}")  # Reduce noise on first run

    def _save_pattern_live(self):
        """Persist tracking data + overrides to disk."""
        try:
            data = {
                'tracking':   self.pattern_live,
                'overrides':  dict(PATTERN_OVERRIDES),
                'updated_at': datetime.datetime.utcnow().isoformat() + 'Z',
            }
            tmp = PATTERN_LIVE_FILE + '.tmp'
            with open(tmp, 'w') as f:
                json.dump(data, f)
                f.flush()
                os.fsync(f.fileno())  # Ensure data written to disk before atomic replace
            os.replace(tmp, PATTERN_LIVE_FILE)
        except Exception as e:
            logger.warning(f"Save pattern_live failed: {e}")

    def _record_pattern_result(self, pattern_key, correct):
        """Append W/L to the rolling window for a pattern."""
        if not pattern_key:
            return
        if pattern_key not in self.pattern_live:
            self.pattern_live[pattern_key] = {
                'results': [], 'updated': '', 'flipped': False
            }
        entry = self.pattern_live[pattern_key]
        entry['results'].append('W' if correct else 'L')
        # Keep only last LIVE_WINDOW results
        if len(entry['results']) > LIVE_WINDOW:
            entry['results'] = entry['results'][-LIVE_WINDOW:]

    def _recalculate_patterns(self):
        """
        Every UPDATE_EVERY_LIVE rounds:
          - Check every tracked pattern's rolling accuracy
          - If accuracy < FLIP_THRESHOLD AND samples >= 8 → flip signal override
          - Save updated tracking data + export updated Excel in background
        """
        self._recent_flips = []
        today = datetime.datetime.utcnow().strftime('%Y-%m-%d %H:%M')

        for pattern_key, entry in self.pattern_live.items():
            results = entry.get('results', [])
            if len(results) < 2:   # minimum 2 samples before acting
                continue

            wins = results.count('W')
            acc  = wins / len(results)

            # Current effective signal for this pattern
            with PATTERN_LOCK:  # THREAD LOCK: protect global state
                if pattern_key in PATTERN_OVERRIDES:
                    cur_sig = PATTERN_OVERRIDES[pattern_key]
                else:
                    match = PATTERN_TABLE.get(pattern_key)
                    if not match:
                        continue
                    cur_sig = 'S' if match[0] >= match[1] else 'B'

                if acc < FLIP_THRESHOLD:
                    # Flip the signal
                    new_sig   = 'B' if cur_sig == 'S' else 'S'
                    old_label = 'SMALL' if cur_sig == 'S' else 'BIG'
                    new_label = 'SMALL' if new_sig == 'S' else 'BIG'
                    PATTERN_OVERRIDES[pattern_key] = new_sig
                    # Reset window after flip so it learns fresh
                    entry['results'] = []
                    entry['flipped'] = True
                    entry['updated'] = today
                    self._recent_flips.append({
                        'pattern': pattern_key,
                        'old': old_label,
                        'new': new_label,
                        'acc': round(acc * 100, 1),
                        'rounds': len(results),
                    })
                    logger.info(
                        f"[FLIP] {pattern_key}: {old_label}→{new_label}  "
                        f"LiveAcc={acc*100:.1f}% over {len(results)} rounds"
                    )
                elif acc >= 0.70:
                    # High confidence — keep override if any, just update timestamp
                    entry['updated'] = today

        if self._recent_flips:
            logger.info(f"[RECALC] {len(self._recent_flips)} pattern(s) flipped this cycle")

        self._save_pattern_live()
        # Export updated Excel in background
        threading.Thread(
            target=self._export_updated_excel, daemon=True
        ).start()

    def _get_live_acc_str(self, pattern_key):
        """Return a concise live accuracy string for the signal message.
        Pattern-level if >= 2 samples exist; else global session accuracy fallback."""
        entry   = self.pattern_live.get(pattern_key, {})
        results = entry.get('results', [])
        if len(results) >= 2:
            wins = results.count('W')
            acc  = round(wins / len(results) * 100, 1)
            return f"LiveAcc:{acc}%({len(results)}r)"
        # Option A fallback: global session accuracy
        total = self.wins + self.losses_total
        if total < 5:
            return None
        acc = round(self.wins / total * 100, 1)
        return f"SessAcc:{acc}%({total}r)"

    def _download_excel_zip_from_github(self):
        """
        GitHub မှ Excel ZIP download လုပ်ပြီး extract, ပြီးရင် PATTERN_TABLE update သည်။
        User က Excel ကို ZIP ချုပ်ပြီး GitHub မှာ တင်ထားသောကြောင့် ဤ function ကို သုံးသည်။
        """
        global PATTERN_TABLE
        token = GITHUB_TOKEN
        if not token:
            return
        try:
            logger.info(f"[EXCEL-ZIP] Checking GitHub for {GITHUB_EXCEL_ZIP}...")
            r = requests.get(
                f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_EXCEL_ZIP}",
                headers={'Authorization': f'token {token}'},
                timeout=15
            )
            if r.status_code == 404:
                logger.info("[EXCEL-ZIP] No Excel ZIP on GitHub yet — using embedded table")
                return
            if r.status_code != 200:
                logger.warning(f"[EXCEL-ZIP] Meta fetch failed: {r.status_code}")
                return

            meta         = r.json()
            download_url = meta.get('download_url')
            if not download_url:
                logger.warning("[EXCEL-ZIP] No download_url in response")
                return

            logger.info(f"[EXCEL-ZIP] Downloading Excel ZIP from GitHub...")
            r2 = requests.get(
                download_url,
                headers={'Authorization': f'token {token}'},
                timeout=120,
                stream=True
            )
            if r2.status_code != 200:
                logger.warning(f"[EXCEL-ZIP] Download failed: {r2.status_code}")
                return

            zip_bytes = b''.join(r2.iter_content(chunk_size=65536))
            logger.info(f"[EXCEL-ZIP] Downloaded {len(zip_bytes)//1024//1024:.1f}MB")

            # Extract Excel from ZIP
            with zipfile.ZipFile(io.BytesIO(zip_bytes)) as zf:
                names = zf.namelist()
                xl_name = next(
                    (n for n in names if n.lower().endswith('.xlsx')), None
                )
                if not xl_name:
                    logger.warning(f"[EXCEL-ZIP] No .xlsx file found in ZIP: {names}")
                    return
                data = zf.read(xl_name)
                with open(EXCEL_LOCAL_PATH, 'wb') as f:
                    f.write(data)
                logger.info(
                    f"[EXCEL-ZIP] Extracted: {xl_name} → {EXCEL_LOCAL_PATH} "
                    f"({len(data)//1024//1024:.1f}MB)"
                )

            # Load pattern table from extracted Excel
            new_table = load_pattern_from_excel(EXCEL_LOCAL_PATH)
            if new_table:
                with PATTERN_LOCK:  # Protect global reassignment
                    PATTERN_TABLE.clear()
                    PATTERN_TABLE.update(new_table)
                logger.info(
                    f"[EXCEL-ZIP] PATTERN_TABLE updated: {len(PATTERN_TABLE)} patterns"
                )
            else:
                logger.warning("[EXCEL-ZIP] Excel loaded but empty — keeping embedded table")

        except Exception as e:
            logger.warning(f"[EXCEL-ZIP] Download/load error: {e}")

    def _upload_excel_zip_to_github(self):
        """
        Local Excel file ကို ZIP ချုပ်ပြီး GitHub မှာ upload သည်。
        _export_updated_excel ပြီးတိုင်း ဤ function ကို background thread မှာ run သည်。
        """
        token = GITHUB_TOKEN
        if not token:
            return
        if not os.path.exists(EXCEL_LOCAL_PATH):
            logger.warning(f"[EXCEL-ZIP] {EXCEL_LOCAL_PATH} not found — skip upload")
            return
        try:
            xl_size_mb = os.path.getsize(EXCEL_LOCAL_PATH) / 1024 / 1024
            logger.info(
                f"[EXCEL-ZIP] Zipping {EXCEL_LOCAL_PATH} ({xl_size_mb:.1f}MB) for GitHub..."
            )
            buf = io.BytesIO()
            with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED, compresslevel=6) as zf:
                zf.write(EXCEL_LOCAL_PATH)
            zip_bytes   = buf.getvalue()
            zip_size_mb = len(zip_bytes) / 1024 / 1024

            # GitHub API has 100MB limit — check before uploading
            if zip_size_mb > 95:
                logger.warning(
                    f"[EXCEL-ZIP] ZIP too large ({zip_size_mb:.1f}MB > 95MB) "
                    f"— use GitHub LFS or reduce Excel size"
                )
                return

            logger.info(f"[EXCEL-ZIP] ZIP size: {zip_size_mb:.1f}MB — uploading to GitHub...")
            zip_b64 = base64.b64encode(zip_bytes).decode()

            # Get existing SHA
            sha = None
            r = requests.get(
                f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_EXCEL_ZIP}",
                headers={'Authorization': f'token {token}'},
                timeout=15
            )
            if r.status_code == 200:
                sha = r.json().get('sha')
            elif r.status_code == 401:
                logger.warning("[EXCEL-ZIP] GitHub auth failed")
                return

            payload = {
                'message': (
                    f'Excel update: {len(PATTERN_TABLE)} patterns '
                    f'| {len(PATTERN_OVERRIDES)} overrides '
                    f'| W{self.wins}/L{self.losses_total}'
                ),
                'content': zip_b64
            }
            if sha:
                payload['sha'] = sha

            r = requests.put(
                f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_EXCEL_ZIP}",
                headers={
                    'Authorization': f'token {token}',
                    'Content-Type':  'application/json',
                },
                json=payload,
                timeout=60
            )
            if r.status_code in (200, 201):
                logger.info(
                    f"[EXCEL-ZIP] GitHub upload OK → {GITHUB_EXCEL_ZIP} "
                    f"({zip_size_mb:.1f}MB)"
                )
            else:
                logger.warning(
                    f"[EXCEL-ZIP] Upload failed: {r.status_code} {r.text[:100]}"
                )
        except Exception as e:
            logger.warning(f"[EXCEL-ZIP] Upload error: {e}")

    def _export_updated_excel(self):
        """Update Mr_Wai_Trading_bot_5num_bot_UPDATED.xlsx with current live data."""
        try:
            import openpyxl
            today = datetime.datetime.utcnow().strftime('%Y-%m-%d')
            xl_path = EXCEL_LOCAL_PATH
            if not os.path.exists(xl_path):
                logger.warning("[EXCEL] Updated Excel file not found, skipping update")
                return
            wb  = openpyxl.load_workbook(xl_path)
            ws  = wb['AllPatterns']
            # Find column indices (row 1 = header)
            hdr = {cell.value: cell.column for cell in ws[1]}
            la_col  = hdr.get('LiveAcc%')
            dp_col  = hdr.get('DataPoints')
            lu_col  = hdr.get('LastUpdated')
            lw_col  = hdr.get('LiveW')
            ll_col  = hdr.get('LiveL')
            sig_col = hdr.get('Signal')
            pat_col = hdr.get('Pattern')
            if not all([la_col, lu_col, sig_col, pat_col]):
                logger.warning("[EXCEL] Missing expected columns in updated Excel")
                return
            updated_count = 0
            for row in ws.iter_rows(min_row=2):
                pat_val = row[pat_col - 1].value
                if not pat_val:
                    continue
                entry = self.pattern_live.get(str(pat_val), {})
                results = entry.get('results', [])
                if results:
                    wins   = results.count('W')
                    losses = len(results) - wins
                    acc    = round(wins / len(results) * 100, 1)
                    row[la_col - 1].value = acc
                    row[lu_col - 1].value = today
                    if dp_col:
                        row[dp_col - 1].value = len(results)
                    if lw_col:
                        row[lw_col - 1].value = wins
                    if ll_col:
                        row[ll_col - 1].value = losses
                    updated_count += 1
                # Reflect override if signal was flipped
                if str(pat_val) in PATTERN_OVERRIDES:
                    new_sig = 'SMALL' if PATTERN_OVERRIDES[str(pat_val)] == 'S' else 'BIG'
                    row[sig_col - 1].value = new_sig
            wb.save(xl_path)
            logger.info(f"[EXCEL] Updated Excel: {updated_count} patterns refreshed → {xl_path}")
            # ZIP updated Excel and upload to GitHub in background
            threading.Thread(
                target=self._upload_excel_zip_to_github, daemon=True
            ).start()
        except ImportError:
            logger.warning("[EXCEL] openpyxl not installed — skipping Excel update")
        except Exception as e:
            logger.warning(f"[EXCEL] Export failed: {e}")

    # ══════════════════════════════════════════════════════════════════════════
    #  GitHub export / history
    # ══════════════════════════════════════════════════════════════════════════
    def _load_trx_history(self):
        token = GITHUB_TOKEN
        if not token:
            return
        try:
            r = requests.get(
                f"https://api.github.com/repos/{GITHUB_REPO}/contents/{HISTORY_FILE}",
                headers={'Authorization': f'token {token}'},
                timeout=15
            )
            if r.status_code == 200:
                content = r.json().get('content', '')
                if content:
                    decoded    = base64.b64decode(content).decode('utf-8')
                    data       = json.loads(decoded)
                    gh_results = data.get('results', [])
                    if gh_results:
                        local  = self.result_history
                        if local and gh_results:
                            overlap   = 0
                            max_check = min(len(gh_results), len(local), 50)
                            for check_len in range(max_check, 0, -1):
                                if gh_results[-check_len:] == local[:check_len]:
                                    overlap = check_len
                                    break
                            merged = (gh_results + local[overlap:]) if overlap > 0 else (gh_results + local)
                        else:
                            merged = gh_results + local
                        merged = merged[-ROLLING_MAX:]
                        self.result_history = merged
                        if self.total_results < len(merged):
                            self.total_results = len(merged)
                        logger.info(f"[HISTORY] Loaded {len(gh_results)} from GitHub, merged={len(self.result_history)}")
            elif r.status_code == 404:
                logger.info("[HISTORY] trx_history.json not found on GitHub yet")
            else:
                logger.warning(f"[HISTORY] Load failed: {r.status_code}")
        except Exception as e:
            logger.warning(f"[HISTORY] Load error: {e}")

    def _save_trx_history(self, max_retries=2):
        token = GITHUB_TOKEN
        if not token:
            return
        for attempt in range(max_retries):
            try:
                sha = None
                try:
                    r = requests.get(
                        f"https://api.github.com/repos/{GITHUB_REPO}/contents/{HISTORY_FILE}",
                        headers={'Authorization': f'token {token}'},
                        timeout=10
                    )
                    if r.status_code == 200:
                        sha = r.json().get('sha')
                    elif r.status_code == 401:
                        return
                except Exception as e:
                    logger.warning(f"[HISTORY] SHA fetch error: {e}")
                data = {
                    'version':    '1.0',
                    'total_count': self.total_results,
                    'results':    self.result_history,
                    'last_issue': self.last_issue or '',
                    'updated_at': datetime.datetime.utcnow().isoformat() + 'Z'
                }
                data_json = json.dumps(data)
                payload   = {
                    'message': f'WaveUp history: {self.total_results} results',
                    'content': base64.b64encode(data_json.encode()).decode()
                }
                if sha:
                    payload['sha'] = sha
                r = requests.put(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{HISTORY_FILE}",
                    headers={'Authorization': f'token {token}', 'Content-Type': 'application/json'},
                    json=payload,
                    timeout=15
                )
                if r.status_code in (200, 201):
                    logger.info(f"[HISTORY] Saved {len(self.result_history)} results to GitHub")
                    return
                else:
                    logger.warning(f"[HISTORY] Save failed ({attempt+1}): {r.status_code}")
                    if attempt < max_retries - 1:
                        time.sleep(3)
            except Exception as e:
                logger.warning(f"[HISTORY] Save error ({attempt+1}): {e}")
                if attempt < max_retries - 1:
                    time.sleep(3)

    def _export_to_github(self, max_retries=2):
        token = GITHUB_TOKEN
        if not token:
            return
        for attempt in range(max_retries):
            try:
                hist     = self.result_history
                n        = len(hist)
                total_t  = self.wins + self.losses_total
                win_rate = round(self.wins / max(total_t, 1) * 100, 1) if total_t > 0 else 0
                last20   = hist[-20:] if n >= 20 else hist
                export   = {
                    'version':         'WaveUp-IssueRef',
                    'exported_at':     datetime.datetime.utcnow().isoformat() + 'Z',
                    'total_results':   self.total_results,
                    'wins':            self.wins,
                    'losses_total':    self.losses_total,
                    'win_rate_pct':    win_rate,
                    'consecutive_losses': self.consecutive_losses,
                    'last10_results':  ''.join(hist[-10:]) if n >= 10 else ''.join(hist),
                    'last20':          {'results': ''.join(last20), 'B': last20.count('B'), 'S': last20.count('S')},
                    'overall':         {'B': hist.count('B'), 'S': hist.count('S')},
                }
                export_json = json.dumps(export, indent=2)
                sha = None
                try:
                    r = requests.get(
                        f"https://api.github.com/repos/{GITHUB_REPO}/contents/{EXPORT_FILE}",
                        headers={'Authorization': f'token {token}'},
                        timeout=10
                    )
                    if r.status_code == 200:
                        sha = r.json().get('sha')
                    elif r.status_code == 401:
                        return
                except Exception as e:
                    logger.warning(f"GitHub SHA fetch error: {e}")
                payload = {
                    'message': f'WaveUp stats: {self.total_results} results W{self.wins}/L{self.losses_total} ({win_rate}%)',
                    'content': base64.b64encode(export_json.encode()).decode()
                }
                if sha:
                    payload['sha'] = sha
                r = requests.put(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{EXPORT_FILE}",
                    headers={'Authorization': f'token {token}', 'Content-Type': 'application/json'},
                    json=payload,
                    timeout=15
                )
                if r.status_code in (200, 201):
                    logger.info(f"GitHub export OK: {self.total_results} results")
                    break
                else:
                    logger.warning(f"GitHub export failed ({attempt+1}): {r.status_code}")
                    if attempt < max_retries - 1:
                        time.sleep(3)
            except Exception as e:
                logger.warning(f"GitHub export error ({attempt+1}): {e}")
                if attempt < max_retries - 1:
                    time.sleep(3)
        # GitHub full state backup
        for attempt in range(max_retries):
            try:
                state      = self._build_state_dict()
                state_json = json.dumps(state)
                sha = None
                try:
                    r = requests.get(
                        f"https://api.github.com/repos/{GITHUB_REPO}/contents/{BACKUP_FILE}",
                        headers={'Authorization': f'token {token}'},
                        timeout=10
                    )
                    if r.status_code == 200:
                        sha = r.json().get('sha')
                    elif r.status_code == 401:
                        return
                except Exception as e:
                    logger.warning(f"GitHub backup SHA fetch error: {e}")
                payload = {
                    'message': f'WaveUp state backup: {self.total_results} results W{self.wins}/L{self.losses_total}',
                    'content': base64.b64encode(state_json.encode()).decode()
                }
                if sha:
                    payload['sha'] = sha
                r = requests.put(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{BACKUP_FILE}",
                    headers={'Authorization': f'token {token}', 'Content-Type': 'application/json'},
                    json=payload,
                    timeout=15
                )
                if r.status_code in (200, 201):
                    logger.info(f"[BACKUP] GitHub state backup OK")
                    return
                else:
                    logger.warning(f"[BACKUP] GitHub backup failed ({attempt+1}): {r.status_code}")
                    if attempt < max_retries - 1:
                        time.sleep(3)
            except Exception as e:
                logger.warning(f"[BACKUP] GitHub backup error ({attempt+1}): {e}")
                if attempt < max_retries - 1:
                    time.sleep(3)

    # ══════════════════════════════════════════════════════════════════════════
    #  GitHub ZIP upload / download
    # ══════════════════════════════════════════════════════════════════════════
    def _export_zip_to_github(self, max_retries=2):
        """
        Pack ZIP_INCLUDE_FILES into a ZIP in memory, then upload to GitHub.
        ZIP ဖိုင် GitHub မှာ တင်ပြီး download ပြန်နိုင်အောင် လုပ်သည်။
        """
        token = GITHUB_TOKEN
        if not token:
            return
        try:
            buf = io.BytesIO()
            with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED) as zf:
                for fname in ZIP_INCLUDE_FILES:
                    if os.path.exists(fname):
                        zf.write(fname)
                        logger.info(f"[ZIP] Adding: {fname} ({os.path.getsize(fname)//1024}KB)")
                    else:
                        logger.info(f"[ZIP] Skip (not found): {fname}")
            zip_bytes   = buf.getvalue()
            zip_b64     = base64.b64encode(zip_bytes).decode()
            zip_size_kb = len(zip_bytes) // 1024
            logger.info(f"[ZIP] Created in-memory ZIP: {zip_size_kb}KB")
        except Exception as e:
            logger.warning(f"[ZIP] Build failed: {e}")
            return

        for attempt in range(max_retries):
            try:
                # Get existing SHA (needed for update)
                sha = None
                r = requests.get(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_ZIP_FILE}",
                    headers={'Authorization': f'token {token}'},
                    timeout=15
                )
                if r.status_code == 200:
                    sha = r.json().get('sha')
                elif r.status_code == 401:
                    logger.warning("[ZIP] GitHub auth failed — check GITHUB_TOKEN")
                    return

                payload = {
                    'message': (
                        f'Bot ZIP update: W{self.wins}/L{self.losses_total} '
                        f'patterns={len(PATTERN_OVERRIDES)} overrides'
                    ),
                    'content': zip_b64
                }
                if sha:
                    payload['sha'] = sha

                r = requests.put(
                    f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_ZIP_FILE}",
                    headers={
                        'Authorization': f'token {token}',
                        'Content-Type':  'application/json',
                    },
                    json=payload,
                    timeout=30
                )
                if r.status_code in (200, 201):
                    logger.info(
                        f"[ZIP] GitHub ZIP upload OK → {GITHUB_ZIP_FILE} "
                        f"({zip_size_kb}KB)"
                    )
                    return
                else:
                    logger.warning(
                        f"[ZIP] Upload failed ({attempt+1}): {r.status_code} "
                        f"{r.text[:120]}"
                    )
                    if attempt < max_retries - 1:
                        time.sleep(5)
            except Exception as e:
                logger.warning(f"[ZIP] Upload error ({attempt+1}): {e}")
                if attempt < max_retries - 1:
                    time.sleep(5)

    def _download_zip_from_github(self):
        """
        GitHub မှ ZIP file download လုပ်ပြီး extract သည်။
        Bot restart ဖြစ်သော်/အသစ်သွင်းသော် ဤ method ကို ခေါ်ပြီး
        pattern_live.json နှင့် wai1_state.json ကို restore လုပ်သည်။
        """
        token = GITHUB_TOKEN
        if not token:
            return
        try:
            r = requests.get(
                f"https://api.github.com/repos/{GITHUB_REPO}/contents/{GITHUB_ZIP_FILE}",
                headers={'Authorization': f'token {token}'},
                timeout=15
            )
            if r.status_code == 404:
                logger.info("[ZIP] No ZIP on GitHub yet — skipping download")
                return
            if r.status_code != 200:
                logger.warning(f"[ZIP] Download meta failed: {r.status_code}")
                return

            meta        = r.json()
            download_url = meta.get('download_url')
            if not download_url:
                logger.warning("[ZIP] No download_url in GitHub response")
                return

            # Stream download
            r2 = requests.get(
                download_url,
                headers={'Authorization': f'token {token}'},
                timeout=60,
                stream=True
            )
            if r2.status_code != 200:
                logger.warning(f"[ZIP] Download failed: {r2.status_code}")
                return

            zip_bytes = b''.join(r2.iter_content(chunk_size=8192))
            logger.info(f"[ZIP] Downloaded {len(zip_bytes)//1024}KB from GitHub")

            # Extract — only safe files (no directory traversal)
            with zipfile.ZipFile(io.BytesIO(zip_bytes)) as zf:
                for name in zf.namelist():
                    # Security: skip paths with directory components
                    safe_name = os.path.basename(name)
                    if not safe_name:
                        continue
                    # Only restore data files — never overwrite running bot code
                    if safe_name in ('pattern_live.json', 'wai1_state.json'):
                        data = zf.read(name)
                        with open(safe_name, 'wb') as f:
                            f.write(data)
                        logger.info(f"[ZIP] Restored: {safe_name} ({len(data)//1024}KB)")
                    else:
                        logger.info(f"[ZIP] Skipped (not a restore target): {safe_name}")

            logger.info("[ZIP] GitHub ZIP restore complete")
        except Exception as e:
            logger.warning(f"[ZIP] Download/extract error: {e}")

    # ══════════════════════════════════════════════════════════════════════════
    #  Main loop
    # ══════════════════════════════════════════════════════════════════════════
    def run(self):
        logger.info("Mr Wai Trading Bot — 5-Number Pattern Formula — Running")
        logger.info("Formula: Last 5 numbers → Pattern lookup → S/B predict")

        while True:
            try:
                games = self.get_live_data()
                if not games or len(games) < 10:
                    time.sleep(10)
                    continue

                latest = games[0]
                try:
                    raw_issue   = str(latest.get('issueNumber', ''))
                    issue       = normalize_issue(raw_issue)
                    current_num = int(latest.get('number', -1))
                except Exception as e:
                    logger.warning(f"Issue parse error: {e}")
                    time.sleep(5)
                    continue

                if current_num < 0:
                    time.sleep(5)
                    continue

                # ── Skip if already processed ──────────────────────────────
                if self.last_issue == issue:
                    time.sleep(0.5)
                    continue

                actual = 'B' if current_num >= 5 else 'S'

                # ── Record to history ──────────────────────────────────────
                self._add_result(actual)

                # ── Calc next issue number ─────────────────────────────────
                try:
                    next_issue_full = str(int(issue) + 1)
                    next_issue_3d   = next_issue_full[-3:] if len(next_issue_full) >= 3 else next_issue_full.zfill(3)
                except Exception as e:
                    logger.warning(f"Next issue calc error: {e}")
                    self.last_issue = issue
                    self._save_state()
                    time.sleep(2)
                    continue

                # ══ CATCH-UP: missed-round WIN/LOSS recovery ══════════════════════
                # If current issue jumped past the one we signaled (e.g. 357→359,
                # skipping 358), look 358's result up from the games history list
                # so WIN/LOSS and pattern_live data are not lost.
                if (self.last_sent_sig and self._last_prediction
                        and self.last_sent_sig != issue):
                    try:
                        sig_int  = int(self.last_sent_sig)
                        curr_int = int(issue)
                        if curr_int > sig_int:
                            for g in games[1:25]:
                                g_iss = normalize_issue(
                                    str(g.get('issueNumber', '')))
                                if g_iss == self.last_sent_sig:
                                    g_num = int(g.get('number', -1))
                                    if g_num >= 0:
                                        g_actual = 'B' if g_num >= 5 else 'S'
                                        if self._last_prediction == g_actual:
                                            self.wins += 1
                                            self.consecutive_losses = 0
                                            self.bet_counter        = 0
                                            # Use stored live_key (captured at prediction time)
                                            if self._last_live_key:  # NULL CHECK
                                                self._record_pattern_result(self._last_live_key, True)
                                            logger.info(
                                                f"[CATCH-UP] WIN on missed {g_iss}")
                                            if self.last_sent_win != g_iss:
                                                self.last_sent_win = g_iss
                                                self.send_msg(
                                                    "🏆  <b>W I N</b>  🏆🔯☘️🎖🏅🍾🍻🥂🍷🍸",
                                                    parse_mode='HTML')
                                        else:
                                            self.losses_total       += 1
                                            self.consecutive_losses += 1
                                            # FIX: Use stored _last_live_key (same as WIN path, with null check)
                                            if self._last_live_key:
                                                self._record_pattern_result(self._last_live_key, False)
                                            else:
                                                logger.warning(f"[CATCH-UP] No live_key for LOSS on {g_iss}")
                                            logger.info(
                                                f"[CATCH-UP] LOSS on missed {g_iss}")
                                        self._last_prediction  = None
                                        self._last_pattern_key = None
                                        self._last_live_key    = None  # clear stale key
                                    break
                    except Exception as e:
                        logger.warning(f"[CATCH-UP] Error processing missed result: {e}")

                # ══ STEP 1: WIN/LOSS for CURRENT issue (FIRST — win msg before signal) ══
                if self.last_sent_sig and self.last_sent_sig == issue:
                    if hasattr(self, '_last_prediction') and self._last_prediction:
                        if self._last_prediction == actual:
                            # ── WIN ────────────────────────────────────────
                            self.wins += 1
                            self.consecutive_losses = 0
                            self.bet_counter        = 0
                            # Use stored live_key (captured at prediction time)
                            if self._last_live_key:  # NULL CHECK: prevent crash if pattern is None
                                self._record_pattern_result(self._last_live_key, True)
                            logger.info(f"WIN! W={self.wins}/L={self.losses_total}")
                            if self.last_sent_win != issue:
                                self.last_sent_win = issue
                                self.send_msg(
                                    "🏆  <b>W I N</b>  🏆🔯☘️🎖🏅🍾🍻🥂🍷🍸",
                                    parse_mode='HTML'
                                )
                        else:
                            # ── LOSS ───────────────────────────────────────
                            self.losses_total       += 1
                            self.consecutive_losses += 1
                            # Use stored live_key (captured at prediction time)
                            if self._last_live_key:  # NULL CHECK: prevent crash if pattern is None
                                self._record_pattern_result(self._last_live_key, False)
                            logger.info(f"LOSS W={self.wins}/L={self.losses_total}")
                        self._last_prediction  = None
                        self._last_pattern_key = None
                        self._last_live_key    = None  # Clear after recording result

                # ══ STEP 2: Signal for NEXT issue (sent within ~15s after win/loss) ══
                self.last_5_nums.append(current_num)
                if len(self.last_5_nums) > 5:
                    self.last_5_nums = self.last_5_nums[-5:]

                pred = None
                if len(self.last_5_nums) >= 5 and self.last_sent_sig != next_issue_full:
                    pattern_key = ','.join(str(n) for n in self.last_5_nums[-5:])
                    
                    with PATTERN_LOCK:  # THREAD LOCK: protect global state during lookup
                        match = PATTERN_TABLE.get(pattern_key)

                        if match:
                            s_count, b_count = match[0], match[1]
                            total = s_count + b_count

                            # ── Check live override first (self-learning flip) ──
                            if pattern_key in PATTERN_OVERRIDES:
                                pred      = PATTERN_OVERRIDES[pattern_key]
                                pred_text = "SMALL" if pred == 'S' else "BIG"
                                conf      = round(s_count / total * 100, 1) if total > 0 else 50.0
                                logger.debug(
                                    f"[PATTERN] {pattern_key} → OVERRIDE={pred} "
                                    f"(orig S={s_count} B={b_count})"
                                )
                            elif s_count > b_count:
                                pred      = 'S'
                                pred_text = "SMALL"
                                conf      = round(s_count / total * 100, 1) if total > 0 else 50.0
                            elif b_count > s_count:
                                pred      = 'B'
                                pred_text = "BIG"
                                conf      = round(b_count / total * 100, 1)
                            else:
                                # Exact tie — Excel rule: always SMALL
                                pred      = 'S'
                                pred_text = "SMALL"
                                conf      = 50.0
                                logger.debug(
                                    f"[PATTERN] {pattern_key} → TIE S={s_count} B={b_count} → SMALL"
                                )

                            if pred:
                                logger.debug(
                                    f"[PATTERN] {pattern_key} → S={s_count} B={b_count} "
                                    f"total={total} → {pred}"
                                )
                        else:
                            # Pattern not found — fallback: opposite of last result
                            if self.result_history and self.result_history[-1] == 'B':
                                pred      = 'S'
                                pred_text = "SMALL"
                            else:
                                pred      = 'B'
                                pred_text = "BIG"
                            conf = 50.0
                            logger.debug(
                                f"[PATTERN] {pattern_key} → not found → fallback={pred}"
                            )

                if pred:
                    self.bet_counter = self.consecutive_losses + 1
                    spaced_text = ' '.join(list(pred_text))
                    bet_dir     = "B" if pred == "B" else "S"
                    bet_label   = f"{bet_dir}{self.bet_counter}"
                    pat_key     = ','.join(str(n) for n in self.last_5_nums)
                    # FIX: Use FULL 5-number key for live tracking (matches PATTERN_TABLE)
                    live_key = ','.join(str(n) for n in self.last_5_nums[-5:])

                    # ── Live accuracy string ───────────────────────────────
                    live_str = self._get_live_acc_str(live_key)
                    acc_part = live_str if live_str else f"Acc:{conf}%"

                    # ── Pattern flip notification (embed in signal) ────────
                    flip_note = ""
                    for flip in list(self._recent_flips):  # snapshot — thread-safe iterate
                        if flip['pattern'] == pat_key:
                            flip_note = (
                                f"\n⚠️ Pattern updated: "
                                f"{flip['old']}→{flip['new']} "
                                f"(was {flip['acc']}% over {flip['rounds']}r)"
                            )
                            break

                    hdr   = "🏦 Mr Wai Trading bot"
                    body  = (
                        f"<b>TRX: {next_issue_3d}  ➤  💥 {spaced_text} "
                        f"{{ {bet_label} }} 💥</b>"
                    )
                    stats = f"📊  [Pattern:{pat_key} | {acc_part}]{flip_note}"
                    
                    # ── CRITICAL FIX: Update prediction state BEFORE saving ────────
                    # Must store live_key at prediction time, before any save
                    self.last_sent_sig     = next_issue_full
                    self._last_prediction  = pred
                    self._last_pattern_key = pat_key
                    self._last_live_key    = live_key  # STORE live_key BEFORE save (so WIN/LOSS uses same key)
                    
                    self.last_issue = issue
                    self._recalc_counter += 1  # Increment counter BEFORE save
                    # FIX: Check recalc threshold in BOTH branches (not just 'else')
                    if self._recalc_counter >= UPDATE_EVERY_LIVE:
                        self._recalc_counter = 0
                        logger.info(
                            f"[SELF-LEARN] {UPDATE_EVERY_LIVE} rounds elapsed — "
                            f"recalculating patterns..."
                        )
                        threading.Thread(
                            target=self._recalculate_patterns, daemon=True
                        ).start()
                    self._save_state()  # Save state with prediction info BEFORE Telegram send
                    # ──────────────────────────────────────────────────────────────
                    
                    sent  = self.send_msg(
                        f"{hdr}\n{body}\n{stats}", parse_mode='HTML'
                    )
                    
                    if sent:
                        logger.info(
                            f"Signal: Trx {next_issue_3d} {pred_text} {conf}% "
                            f"[{self.bet_counter}x] {acc_part}"
                        )
                    else:
                        # Signal send failed — clear prediction state since we couldn't notify
                        self.last_sent_sig     = None
                        self._last_prediction  = None
                        self._last_pattern_key = None
                        self._last_live_key    = None
                else:
                    # No signal — just update and save
                    self.last_issue = issue
                    self._recalc_counter += 1
                    if self._recalc_counter >= UPDATE_EVERY_LIVE:
                        self._recalc_counter = 0
                        logger.info(
                            f"[SELF-LEARN] {UPDATE_EVERY_LIVE} rounds elapsed — "
                            f"recalculating patterns..."
                        )
                        threading.Thread(
                            target=self._recalculate_patterns, daemon=True
                        ).start()
                    self._save_state()

                time.sleep(0.5)

            except KeyboardInterrupt:
                logger.info("Stopped")
                raise
            except Exception as e:
                logger.error(f"Loop error: {e}")
                time.sleep(10)


def main():
    bot = WaveUpBot()
    try:
        if not bot.bootstrap_history():
            logger.warning("Bootstrap failed, continuing")
    except Exception as e:
        logger.warning(f"Bootstrap exception: {e}")
    bot.run()

if __name__ == "__main__":
    main()
